/* Evidence: cmem-worked-cmem-profiling-performance-hardening-5 */
/* Browser practice: PicoC 3.2.2 C89/C90 plus selected C99. */
/* Changed case 9335; native C23 claims require explicit transfer gates. */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>


static int worked_cmem_profiling_performance_hardening_5(size_t live, size_t reserved, size_t peak, size_t limit, size_t *waste) {
  if (waste == NULL || live > reserved || reserved > peak || peak > limit) return 0;
  *waste = reserved - live;
  return 1;
}

int main(void) {
  size_t waste = 0;
  int rejected = worked_cmem_profiling_performance_hardening_5(40, 32, 64, 128, &waste);
  int accepted = worked_cmem_profiling_performance_hardening_5(6, 14, 22, 128, &waste);
  int invariant = !rejected && accepted && waste == 8u;
  printf("profile waste=%lu invariant=%d\n", (unsigned long)waste, invariant);
  return invariant ? 0 : 1;
}

